import * as fs from "node:fs";
import * as path from "node:path";
import type { MemoryObject } from "./memoryTypes";

interface OllamaCandidateArtifact {
  artifactId: string;
  projectId: string;
  sourceIds: string[];
  model: string;
  promptIntent: string;
  truthLane: "public" | "semi_private" | "private";
  responseText: string;
  status: "candidate";
  createdAt: string;
}

function ensureDir(dir: string): void {
  fs.mkdirSync(dir, { recursive: true });
}

function readJsonFile<T>(filePath: string): T {
  const raw = fs.readFileSync(filePath, "utf8").replace(/^\uFEFF/, "");
  return JSON.parse(raw) as T;
}

function candidateDir(): string {
  const dir = path.resolve(process.cwd(), "shared-core", "governed-runtime", "store", "ollama-candidates");
  ensureDir(dir);
  return dir;
}

function memoryDir(): string {
  const dir = path.resolve(process.cwd(), "shared-core", "governed-runtime", "store", "memory");
  ensureDir(dir);
  return dir;
}

export function ingestOllamaCandidate(fileName: string): string {
  const sourcePath = path.join(candidateDir(), fileName);
  const artifact = readJsonFile<OllamaCandidateArtifact>(sourcePath);

  const now = new Date().toISOString();
  const memoryId = `${artifact.artifactId}_memory`;

  const memoryObject: MemoryObject = {
    id: memoryId,
    projectId: artifact.projectId,
    title: `Ollama Candidate - ${artifact.promptIntent}`,
    summary: "Candidate output generated by local Ollama processor and staged for review.",
    content: artifact.responseText,
    objectClass: "note",
    scope: "project",
    verification: "unverified",
    promotion: "candidate",
    truthLane: artifact.truthLane,
    tags: [
      "ollama_candidate",
      "needs_review",
      "processor_output",
      artifact.model
    ],
    sourceRefs: [artifact.artifactId, ...artifact.sourceIds],
    createdAt: now,
    updatedAt: now
  };

  const outPath = path.join(memoryDir(), `${memoryId}.memory.json`);
  fs.writeFileSync(outPath, JSON.stringify(memoryObject, null, 2), "utf8");
  return outPath;
}
